private static (LogLevel Level, string Prefix) ParseLogLevel(string? logLevel) => logLevel?.ToUpperInvariant() switch
    {
        "TRACE" => (LogLevel.Trace, "TRC"),
        "DEBUG" => (LogLevel.Debug, "DBG"),
        "INFORMATION" or "INFO" => (LogLevel.Information, "INF"),
        "WARNING" or "WARN" => (LogLevel.Warning, "WRN"),
        "ERROR" => (LogLevel.Error, "ERR"),
        "CRITICAL" => (LogLevel.Critical, "CRT"),
        null or _ => (LogLevel.Information, "INF")
    };

public static string GetSeverityText(int? severityNumber)
    {
        return severityNumber switch
        {
            >= 21 => CliLogFormat.FileLevelTokens.Critical,
            >= 17 => CliLogFormat.FileLevelTokens.Error,
            >= 13 => CliLogFormat.FileLevelTokens.Warning,
            >= 9 => CliLogFormat.FileLevelTokens.Information,
            >= 5 => CliLogFormat.FileLevelTokens.Debug,
            >= 1 => CliLogFormat.FileLevelTokens.Trace,
            _ => "-"
        };
    }

public static Color GetSeverityColor(int? severityNumber)
    {
        return severityNumber switch
        {
            >= 17 => Color.Red,      // ERROR/FATAL
            >= 13 => Color.Yellow,   // WARN
            >= 9 => Color.Blue,      // INFO
            >= 5 => Color.Grey,      // DEBUG
            >= 1 => Color.Grey,      // TRACE
            _ => Color.White
        };
    }

