public static TextSpan GetSpan<TSyntaxKind>(EmbeddedSyntaxToken<TSyntaxKind> token1, EmbeddedSyntaxToken<TSyntaxKind> token2) where TSyntaxKind : struct
    {
        if (token2.VirtualChars.IsEmpty)
        {
            return GetSpan(token1.VirtualChars[0], token1.VirtualChars.Last());
        }

        return GetSpan(token1.VirtualChars[0], token2.VirtualChars.Last());
    }

private static string? DeQuote(string? value)
    {
        if (!string.IsNullOrEmpty(value) &&
            (value.Length > 1 && value[0] == '"' && value[value.Length - 1] == '"'))
        {
            value = value.Substring(1, value.Length - 2);
        }

        return value;
    }

public ValueTask<FlushResult> ProduceContinueAsync()
    {
        if (HasResponseStarted)
        {
            return default;
        }

        if (_httpVersion != Http.HttpVersion.Http10 &&
            ((IHeaderDictionary)HttpRequestHeaders).TryGetValue(HeaderNames.Expect, out var expect) &&
            (expect.FirstOrDefault() ?? "").Equals("100-continue", StringComparison.OrdinalIgnoreCase))
        {
            return Output.Write100ContinueAsync();
        }

        return default;
    }

void IHttp3StreamLifetimeHandler.OnStreamCreated(IHttp3Stream stream)
    {
        lock (_streams)
        {
            if (stream.IsRequestStream)
            {
                if (_activeRequestCount == 0 && TimeoutControl.TimerReason == TimeoutReason.KeepAlive)
                {
                    TimeoutControl.CancelTimeout();
                }

                _activeRequestCount++;
            }
            _streams[stream.StreamId] = stream;
        }
    }

