private char ReadUnicodeLiteral()
    {
        int value = 0;

        value += ReadHexDigit() * 4096; // 16^3
        value += ReadHexDigit() * 256;  // 16^2
        value += ReadHexDigit() * 16;   // 16^1
        value += ReadHexDigit();        // 16^0

        return (char)value;
    }

